                rx_chain.ddc->get_frequency_range(rx_chain.block_chan),
                rx_chain.rf_core->get_rx_bandwidth(rx_chain.block_chan))
                           : get_fe_rx_freq_range(chan);
        return dsp_freq_range;
    }

